class MinStack {
  constructor() {
    this.st = [];
    this.mins = [];
  }
  push(x) {
    this.st.push(x);
    if (!this.mins.length || x <= this.mins[this.mins.length - 1]) this.mins.push(x);
    else this.mins.push(this.mins[this.mins.length - 1]);
  }
  pop() {
    this.mins.pop();
    return this.st.pop();
  }
  top() {
    return this.st[this.st.length - 1];
  }
  getMin() {
    return this.mins[this.mins.length - 1];
  }
}

tests:
const m = new MinStack();
m.push(3); m.push(5);
if (m.getMin() !== 3) throw new Error('min should be 3');
m.push(2); m.push(1);
if (m.getMin() !== 1) throw new Error('min should be 1');
if (m.pop() !== 1) throw new Error('pop should be 1');
if (m.getMin() !== 2) throw new Error('min should be 2');
if (m.top() !== 2) throw new Error('top should be 2');
m.pop();
if (m.getMin() !== 3) throw new Error('min should be 3 again');

