function toBinary(n) {
  if (n === 0) return '0';
  const st = [];
  while (n > 0) {
    st.push(n % 2);
    n = Math.floor(n / 2);
  }
  let out = '';
  while (st.length) out += st.pop();
  return out;
}

tests:
