function dailyTemps(temps) {
  const res = new Array(temps.length).fill(0);
  const st = [];
  for (let i = 0; i < temps.length; i++) {
    while (st.length && temps[st[st.length - 1]] < temps[i]) {
      const j = st.pop();
      res[j] = i - j;
    }
    st.push(i);
  }
  return res;
}

