class Queue {
  constructor() {
    this.inSt = [];
    this.outSt = [];
  }
  enqueue(x) {
    this.inSt.push(x);
  }
  dequeue() {
    if (!this.outSt.length) {
      while (this.inSt.length) this.outSt.push(this.inSt.pop());
    }
    return this.outSt.pop();
  }
}

